import "./hover-card.css";

import { HoverCard } from "radix-ui";

export type HoverCardRootProps = React.ComponentProps<typeof HoverCard.Root>;

export const HoverCardRoot = (props: HoverCardRootProps) => {
  return <HoverCard.Root {...props} />;
};

import { HoverCard } from "radix-ui";

export type HoverCardTriggerProps = React.ComponentProps<typeof HoverCard.Trigger>;

export const HoverCardTrigger = (props: HoverCardTriggerProps) => {
  return <HoverCard.Trigger asChild {...props} />;
};

import { HoverCard } from "radix-ui";
import { cn } from "tailwind-variants";

import { hoverCardVariants } from "./hover-card.variants";

export type HoverCardContentProps = React.ComponentProps<typeof HoverCard.Content>;

export const HoverCardContent = ({
  className,
  sideOffset = 4,
  ...props
}: HoverCardContentProps) => {
  const { content } = hoverCardVariants();

  return (
    <HoverCard.Portal>
      <HoverCard.Content className={cn(content(), className)} sideOffset={sideOffset} {...props} />
    </HoverCard.Portal>
  );
};

import { tv, type VariantProps } from "tailwind-variants";

export const hoverCardVariants = tv({
  slots: {
    content: "hover-card__content",
  },
});

export type HoverCardVariants = VariantProps<typeof hoverCardVariants>;

.hover-card__content {
  @apply bg-popover text-popover-foreground z-50 w-64 rounded-md border p-4 shadow-md outline-none;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }

  &[data-side="bottom"] {
    @apply slide-in-from-top-2;
  }

  &[data-side="left"] {
    @apply slide-in-from-right-2;
  }

  &[data-side="right"] {
    @apply slide-in-from-left-2;
  }

  &[data-side="top"] {
    @apply slide-in-from-bottom-2;
  }
}

import { HoverCardContent } from "./hover-card-content";
import { HoverCardRoot } from "./hover-card-root";
import { HoverCardTrigger } from "./hover-card-trigger";

export const HoverCard = {
  Content: HoverCardContent,
  Root: HoverCardRoot,
  Trigger: HoverCardTrigger,
};

export { HoverCardContent, HoverCardRoot, HoverCardTrigger };

export type { HoverCardContentProps } from "./hover-card-content";

export type { HoverCardRootProps } from "./hover-card-root";
export type { HoverCardTriggerProps } from "./hover-card-trigger";
export { type HoverCardVariants, hoverCardVariants } from "./hover-card.variants";
